#include <bits/stdc++.h>
using namespace std;
int na;
const int maxn=1e8+5;
int s;
bool a[maxn];
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>na;
	s=na-1;
	for(int i=2; i*i<=na; i++) {
		if(a[i]==0) {
			for(int j=i*2; j<=na; j+=i) {
				if(a[j]==0) {
					a[j]=1;
					s--;
				}
			}
		}
	}
	cout<<s;
	return 0;
}
